CREATE VIEW vw_tissues WITH (security_invoker = ON) AS
SELECT
  t.tissue_id,                                                                  -- Stable identifier for each tissue type.
  t.tissue_label,                                                               -- Human-readable tissue name (blood, gut, synovium, skin, brain).
  calc_tissues_name(t.tissue_id) AS name,                                       -- Display label for the tissue.
  calc_tissues_count_of_omics_assays(t.tissue_id) AS count_of_omics_assays,     -- Number of omics assays performed on this tissue.
