CREATE VIEW vw_federated_datasets WITH (security_invoker = ON) AS
SELECT
  t.federated_dataset_id,                                                       -- Stable identifier for each federated data node.
  t.node_label,                                                                 -- Human-readable federated node name.
  t.region,                                                                     -- Geographic region; shifting environments may alter exposure profiles.
  t.is_privacy_preserving,                                                      -- True when node uses privacy-preserving federated learning.
  calc_federated_datasets_name(t.federated_dataset_id) AS name,                 -- Display label for the federated dataset.
  calc_federated_datasets_count_of_individuals(t.federated_dataset_id) AS count_of_individuals,-- Individuals enrolled via this federated node.
  t.individuals,                                                                -- Individuals linked to this federated dataset.
  t.omics_assays,                                                               -- Omics assays sourced from this node.
  t.cohort_replications                                                         -- Replications run in this cohort node.
FROM federated_datasets t;

