  t.ancestry_label,                                                             -- Ancestry label for population stratification and ancestry-equitable risk prediction.
  t.age_years,                                                                  -- Age in years spanning development and aging windows.
  t.is_ancestry_absent_from_training,                                           -- True when individual ancestry was absent from primary training data.
  t.federated_dataset,                                                          -- Federated dataset node when enrolled via privacy-preserving federation.
  t.enrollment_date,                                                            -- Longitudinal cohort enrollment date.
  t.has_cryptic_relatedness_flag,                                               -- True when cryptic relatedness or assortative mating bias detected.
  calc_individuals_name(t.individual_id) AS name,                               -- Display name for the individual.
  calc_individuals_federated_dataset_node_label(t.individual_id) AS federated_dataset_node_label,-- Lookup of federated node label.
  calc_individuals_count_of_genomic_variants(t.individual_id) AS count_of_genomic_variants,-- Total genomic variants for rare-variant burden assessment.
  calc_individuals_count_of_causal_mechanisms(t.individual_id) AS count_of_causal_mechanisms,-- Inferred causal mechanisms linked to this individual.
  calc_individuals_count_of_epistatic_interactions(t.individual_id) AS count_of_epistatic_interactions,-- Higher-order epistasis interactions involving this individual.
  calc_individuals_rare_variant_burden_score(t.individual_id) AS rare_variant_burden_score,-- 2nd-order score from rare variant count normalized by age.
  calc_individuals_causal_architecture_score(t.individual_id) AS causal_architecture_score,-- 3rd-order composite of causal mechanisms and epistasis density.
  calc_individuals_is_development_window(t.individual_id) AS is_development_window,-- True when age falls in developmental effects window (0-25).
  calc_individuals_is_aging_window(t.individual_id) AS is_aging_window,         -- True when age falls in aging window (60+).
  calc_individuals_count_confirmed_causal_nodes(t.individual_id) AS count_confirmed_causal_nodes,-- Count of this individual's confirmed causal-architecture nodes.
  calc_individuals_sum_confirmed_causal_confidence(t.individual_id) AS sum_confirmed_causal_confidence,-- Summed confidence of this individual's confirmed causal nodes (derived causal mass).
  calc_individuals_count_cross_ancestry_confirmed_nodes(t.individual_id) AS count_cross_ancestry_confirmed_nodes,-- Confirmed nodes that also showed cross-ancestry replication.
  t.genomic_variants,                                                           -- Genomic variants for this individual.
  t.omics_assays,                                                               -- Omics assays for this individual.
  t.environmental_exposures,                                                    -- Longitudinal environmental exposures.
  t.treatments,                                                                 -- Treatment histories.
  t.clinical_phenotypes,                                                        -- Clinical phenotypes.
  t.causal_mechanisms,                                                          -- Inferred causal mechanisms.
  t.epistatic_interactions,                                                     -- Epistatic interactions.
  t.counterfactual_trajectories,                                                -- Counterfactual trajectories.
  t.individual_predictions                                                      -- Individual predictions.
FROM individuals t;

-- ----------------------------------------------------------------------------
-- vw_genomic_variants: Genomic variant calls per individual spanning regulatory, coding, structural, HLA haplotypes, de novo mutations, somatic mosaicism, and mitochondrial variation.
