  t.individual,                                                                 -- Individual assayed.
  t.omics_modality,                                                             -- Omics modality used.
  t.tissue,                                                                     -- Tissue sampled; empty when missing tissues.
  t.federated_dataset,                                                          -- Source federated node if applicable.
  t.batch_id,                                                                   -- Sequencing batch for batch effects control.
  t.measurement_error_score,                                                    -- Estimated measurement error (0-1).
  t.has_cell_state_specific_effect,                                             -- True when cell-state-specific effects detected.
  calc_omics_assays_name(t.omics_assay_id) AS name,                             -- Display label.
  calc_omics_assays_modality_label(t.omics_assay_id) AS modality_label,         -- Lookup of modality label.
  calc_omics_assays_tissue_label(t.omics_assay_id) AS tissue_label,             -- Lookup of tissue label.
  calc_omics_assays_has_batch_effect_risk(t.omics_assay_id) AS has_batch_effect_risk,-- True when measurement error exceeds 0.3.
  calc_omics_assays_is_high_quality_assay(t.omics_assay_id) AS is_high_quality_assay,-- 2nd-order quality flag.
  t.evidence_items                                                              -- Evidence items measured in this assay.
